/// C: `static int db_setcstacklimit(lua_State *L)`
pub(crate) fn set_c_stack_limit(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: int limit = (int)luaL_checkinteger(L, 1);
    let limit = state.check_arg_integer(1)? as i32;
